        _dbSet = _dbContext.Set<TEntity>();
    }

    // Other methods...

    public async Task<TEntity> FindByDynamicFieldAsync(Expression<Func<TEntity, bool>> expression)
    {
        return await _dbSet.AsNoTracking().FirstOrDefaultAsync(expression);
    }

    public async Task<IEnumerable<TEntity>> FindByDynamicFieldAsyncEnumerable(Expression<Func<TEntity, bool>> expression)
    {
        return await _dbSet.AsNoTracking().Where(expression).ToListAsync();
    }

    public TEntity FindByDynamicField(Expression<Func<TEntity, bool>> expression)
    {
        return _dbSet.AsNoTracking().FirstOrDefault(expression);
    }

